import{_ as t,c as o,o as i,a1 as r}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse(`{"title":"Initialisation du projet | opencode-supermemory","description":"Apprenez à utiliser /supermemory-init pour analyser le dépôt, extraire l'architecture et stocker les conventions dans une mémoire persistante.","frontmatter":{"title":"Initialisation du projet | opencode-supermemory","sidebarTitle":"Initialisation","subtitle":"Initialisation du projet : Créer une première impression","description":"Apprenez à utiliser /supermemory-init pour analyser le dépôt, extraire l'architecture et stocker les conventions dans une mémoire persistante.","tags":["Initialisation","Génération de mémoire","Flux de travail"],"prerequisite":["start-getting-started"],"order":2},"headers":[],"relativePath":"fr/supermemoryai/opencode-supermemory/start/initialization/index.md","filePath":"fr/supermemoryai/opencode-supermemory/start/initialization/index.md"}`),s={name:"fr/supermemoryai/opencode-supermemory/start/initialization/index.md"};function a(n,e,l,u,c,d){return i(),o("div",null,[...e[0]||(e[0]=[r(`<h1 id="initialisation-du-projet-creer-une-premiere-impression" tabindex="-1">Initialisation du projet : Créer une première impression <a class="header-anchor" href="#initialisation-du-projet-creer-une-premiere-impression" aria-label="Permalink to &quot;Initialisation du projet : Créer une première impression&quot;">​</a></h1><h2 id="ce-que-vous-pourrez-faire-apres-ce-cours" tabindex="-1">Ce que vous pourrez faire après ce cours <a class="header-anchor" href="#ce-que-vous-pourrez-faire-apres-ce-cours" aria-label="Permalink to &quot;Ce que vous pourrez faire après ce cours&quot;">​</a></h2><ul><li><strong>Familiarisation instantanée du projet</strong> : Laissez l&#39;Agent explorer et comprendre l&#39;ensemble du dépôt de code comme un nouvel employé.</li><li><strong>Création de mémoire à long terme</strong> : Extraitz automatiquement la pile technologique, les modèles d&#39;architecture et les conventions de codage du projet, et stockez-les dans Supermemory.</li><li><strong>Élimination des explications répétitives</strong> : N&#39;ayez plus besoin de répéter &quot;nous utilisons Bun&quot; ou &quot;tous les composants doivent avoir des tests&quot; au début de chaque session.</li></ul><h2 id="votre-situation-actuelle" tabindex="-1">Votre situation actuelle <a class="header-anchor" href="#votre-situation-actuelle" aria-label="Permalink to &quot;Votre situation actuelle&quot;">​</a></h2><p>Avez-vous rencontré ces situations :</p><ul><li><strong>Travail répétitif</strong> : À chaque nouvelle session, vous devez passer beaucoup de temps à expliquer à l&#39;Agent les bases du projet.</li><li><strong>Oubli de contexte</strong> : L&#39;Agent oublie souvent la structure des répertoires spécifique au projet et crée des fichiers au mauvais endroit.</li><li><strong>Incohérence des conventions</strong> : Le code écrit par l&#39;Agent a un style incohérent, utilisant parfois <code>interface</code> et parfois <code>type</code>.</li></ul><h2 id="quand-utiliser-cette-approche" tabindex="-1">Quand utiliser cette approche <a class="header-anchor" href="#quand-utiliser-cette-approche" aria-label="Permalink to &quot;Quand utiliser cette approche&quot;">​</a></h2><ul><li><strong>Juste après l&#39;installation du plugin</strong> : C&#39;est la première étape de l&#39;utilisation d&#39;opencode-supermemory.</li><li><strong>Lorsque vous reprenez un nouveau projet</strong> : Créez rapidement une base de mémoire pour ce projet.</li><li><strong>Après une refonte majeure</strong> : Lorsque l&#39;architecture du projet change et que vous devez mettre à jour la compréhension de l&#39;Agent.</li></ul><h2 id="🎒-preparation-avant-de-commencer" tabindex="-1">🎒 Préparation avant de commencer <a class="header-anchor" href="#🎒-preparation-avant-de-commencer" aria-label="Permalink to &quot;🎒 Préparation avant de commencer&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Vérification préalable</p><p>Assurez-vous d&#39;avoir terminé les étapes d&#39;installation et de configuration dans <a href="./../getting-started/">Démarrage rapide</a> et que <code>SUPERMEMORY_API_KEY</code> est correctement configuré.</p></div><h2 id="idee-principale" tabindex="-1">Idée principale <a class="header-anchor" href="#idee-principale" aria-label="Permalink to &quot;Idée principale&quot;">​</a></h2><p>La commande <code>/supermemory-init</code> n&#39;est pas essentiellement un programme binaire, mais un <strong>prompt soigneusement conçu</strong> (invite).</p><p>Lorsque vous exécutez cette commande, elle envoie à l&#39;Agent un &quot;guide d&#39;intégration&quot; détaillé, indiquant à l&#39;Agent :</p><ol><li><strong>Recherche approfondie</strong> : Lire activement <code>README.md</code>, <code>package.json</code>, l&#39;historique des commits Git, etc.</li><li><strong>Analyse structurée</strong> : Identifier la pile technologique, les modèles d&#39;architecture et les conventions implicites du projet.</li><li><strong>Stockage persistant</strong> : Utiliser l&#39;outil <code>supermemory</code> pour stocker ces aperçus dans la base de données cloud.</li></ol><div class="info custom-block"><p class="custom-block-title">Portée de la mémoire</p><p>Le processus d&#39;initialisation distingue deux types de mémoire :</p><ul><li><strong>Project Scope</strong> : S&#39;applique uniquement au projet actuel (comme : commandes de build, structure des répertoires).</li><li><strong>User Scope</strong> : S&#39;applique à tous vos projets (comme : votre style de codage préféré).</li></ul></div><h2 id="suivez-moi" tabindex="-1">Suivez-moi <a class="header-anchor" href="#suivez-moi" aria-label="Permalink to &quot;Suivez-moi&quot;">​</a></h2><h3 id="etape-1-executer-la-commande-d-initialisation" tabindex="-1">Étape 1 : Exécuter la commande d&#39;initialisation <a class="header-anchor" href="#etape-1-executer-la-commande-d-initialisation" aria-label="Permalink to &quot;Étape 1 : Exécuter la commande d&#39;initialisation&quot;">​</a></h3><p>Dans la zone de saisie OpenCode, entrez la commande suivante et envoyez :</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/supermemory-init</span></span></code></pre></div><p><strong>Pourquoi</strong> Cela charge le prompt prédéfini et lance le mode d&#39;exploration de l&#39;Agent.</p><p><strong>Ce que vous devriez voir</strong> L&#39;Agent commence à répondre, indiquant qu&#39;il comprend la tâche et commence à planifier les étapes de recherche. Il pourrait dire : &quot;I will start by exploring the codebase structure and configuration files...&quot;</p><h3 id="etape-2-observer-le-processus-d-exploration-de-l-agent" tabindex="-1">Étape 2 : Observer le processus d&#39;exploration de l&#39;Agent <a class="header-anchor" href="#etape-2-observer-le-processus-d-exploration-de-l-agent" aria-label="Permalink to &quot;Étape 2 : Observer le processus d&#39;exploration de l&#39;Agent&quot;">​</a></h3><p>L&#39;Agent exécutera automatiquement une série d&#39;opérations, vous n&#39;avez qu&#39;à regarder. Il fera généralement :</p><ol><li><strong>Lire les fichiers de configuration</strong> : Lire <code>package.json</code>, <code>tsconfig.json</code>, etc. pour comprendre la pile technologique.</li><li><strong>Voir l&#39;historique Git</strong> : Exécuter <code>git log</code> pour comprendre les conventions de commit et les contributeurs actifs.</li><li><strong>Explorer la structure des répertoires</strong> : Utiliser <code>ls</code> ou <code>list_files</code> pour voir la disposition du projet.</li></ol><p><strong>Exemple de sortie</strong> :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Agent] Reading package.json to identify dependencies...</span></span>
<span class="line"><span>[Agent] Running git log to understand commit conventions...</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Attention à la consommation</p><p>Ce processus est une recherche approfondie et peut consommer beaucoup de tokens (généralement 50+ appels d&#39;outils). Soyez patient jusqu&#39;à ce que l&#39;Agent signale la fin.</p></div><h3 id="etape-3-verifier-les-memoires-generees" tabindex="-1">Étape 3 : Vérifier les mémoires générées <a class="header-anchor" href="#etape-3-verifier-les-memoires-generees" aria-label="Permalink to &quot;Étape 3 : Vérifier les mémoires générées&quot;">​</a></h3><p>Lorsque l&#39;Agent indique que l&#39;initialisation est terminée, vous pouvez vérifier ce qu&#39;il a mémorisé. Entrez :</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/ask</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Lister</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> les</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mémoires</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> du</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> projet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> actuel</span></span></code></pre></div><p>Ou appelez directement l&#39;outil (si vous voulez voir les données brutes) :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>supermemory(mode: &quot;list&quot;, scope: &quot;project&quot;)</span></span></code></pre></div><p><strong>Ce que vous devriez voir</strong> L&#39;Agent liste une série de mémoires structurées, par exemple :</p><table tabindex="0"><thead><tr><th>Type</th><th>Exemple de contenu</th></tr></thead><tbody><tr><td><code>project-config</code></td><td>&quot;Uses Bun runtime. Build command: bun run build&quot;</td></tr><tr><td><code>architecture</code></td><td>&quot;API routes are located in src/routes/, using Hono framework&quot;</td></tr><tr><td><code>preference</code></td><td>&quot;Strict TypeScript usage: no &#39;any&#39; type allowed&quot;</td></tr></tbody></table><h3 id="etape-4-completer-les-omissions-optionnel" tabindex="-1">Étape 4 : Compléter les omissions (optionnel) <a class="header-anchor" href="#etape-4-completer-les-omissions-optionnel" aria-label="Permalink to &quot;Étape 4 : Compléter les omissions (optionnel)&quot;">​</a></h3><p>Si l&#39;Agent a manqué certaines informations clés (comme une règle spécifique qui n&#39;a été convenue qu&#39;oralement), vous pouvez la compléter manuellement :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>S&#39;il te plaît, souviens-toi : dans ce projet, tout le traitement des dates doit utiliser la bibliothèque dayjs, l&#39;utilisation de Date natif est interdite.</span></span></code></pre></div><p><strong>Ce que vous devriez voir</strong> L&#39;Agent confirme et appelle <code>supermemory(mode: &quot;add&quot;)</code> pour sauvegarder cette nouvelle règle.</p><h2 id="point-de-controle-✅" tabindex="-1">Point de contrôle ✅ <a class="header-anchor" href="#point-de-controle-✅" aria-label="Permalink to &quot;Point de contrôle ✅&quot;">​</a></h2><ul><li>[ ] Après avoir exécuté <code>/supermemory-init</code>, l&#39;Agent a-t-il automatiquement exécuté la tâche d&#39;exploration ?</li><li>[ ] Pouvez-vous voir les nouvelles mémoires créées avec la commande <code>list</code> ?</li><li>[ ] Le contenu de la mémoire reflète-t-il fidèlement la situation réelle du projet actuel ?</li></ul><h2 id="pieges-courants" tabindex="-1">Pièges courants <a class="header-anchor" href="#pieges-courants" aria-label="Permalink to &quot;Pièges courants&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Ne lancez pas fréquemment</p><p>L&#39;initialisation est un processus chronophage et consommateur de tokens. Habituellement, chaque projet ne doit être exécuté qu&#39;une seule fois. Ne le relancez que lorsque le projet subit des changements majeurs.</p></div><div class="danger custom-block"><p class="custom-block-title">Attention à la confidentialité</p><p>Bien que le plugin masque automatiquement le contenu des balises <code>&lt;private&gt;</code>, lors du processus d&#39;initialisation, l&#39;Agent lira de nombreux fichiers. Assurez-vous qu&#39;il n&#39;y a pas de clés sensibles codées en dur dans votre dépôt de code (comme AWS Secret Key), sinon elles pourraient être stockées dans la mémoire en tant que &quot;configuration du projet&quot;.</p></div><h2 id="resume-du-cours" tabindex="-1">Résumé du cours <a class="header-anchor" href="#resume-du-cours" aria-label="Permalink to &quot;Résumé du cours&quot;">​</a></h2><p>Grâce à <code>/supermemory-init</code>, nous avons accompli la transition de &quot;étranger&quot; à &quot;employé expérimenté&quot;. Maintenant, l&#39;Agent a mémorisé l&#39;architecture principale et les conventions du projet, et dans les tâches de codage à venir, il utilisera automatiquement ces informations pour vous fournir une assistance plus précise.</p><h2 id="apercu-du-prochain-cours" tabindex="-1">Aperçu du prochain cours <a class="header-anchor" href="#apercu-du-prochain-cours" aria-label="Permalink to &quot;Aperçu du prochain cours&quot;">​</a></h2><blockquote><p>Le prochain cours est <strong><a href="./../../core/context-injection/">Mécanisme d&#39;injection automatique de contexte</a></strong>.</p><p>Vous apprendrez :</p><ul><li>Comment l&#39;Agent &quot;rappelle&quot; ces mémoires au début d&#39;une session.</li><li>Comment déclencher le rappel de mémoires spécifiques par des mots-clés.</li></ul></blockquote><hr><h2 id="annexe-reference-du-code-source" tabindex="-1">Annexe : Référence du code source <a class="header-anchor" href="#annexe-reference-du-code-source" aria-label="Permalink to &quot;Annexe : Référence du code source&quot;">​</a></h2><details><summary><strong>Cliquez pour voir les emplacements du code source</strong></summary><blockquote><p>Date de mise à jour : 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Fonctionnalité</th><th>Chemin du fichier</th><th>Lignes</th></tr></thead><tbody><tr><td>Définition du prompt d&#39;initialisation</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/cli.ts#L13-L163" target="_blank" rel="noreferrer"><code>src/cli.ts</code></a></td><td>13-163</td></tr><tr><td>Implémentation de l&#39;outil de mémoire</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L183-L485" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>183-485</td></tr></tbody></table><p><strong>Constantes clés</strong> :</p><ul><li><code>SUPERMEMORY_INIT_COMMAND</code> : Définit le contenu spécifique du prompt pour la commande <code>/supermemory-init</code>, guidant l&#39;Agent sur comment effectuer la recherche et la mémorisation.</li></ul></details>`,50)])])}const h=t(s,[["render",a]]);export{m as __pageData,h as default};
